mapper.select:
SELECT e.id, e.username, e.password, e.name, e.gender, e.phone, e.job, e.salary, e.image, e.entry_date, e.dept_id, e.create_time, e.update_time, d.name AS dept_name FROM emp e LEFT JOIN dept d ON e.dept_id = d.id WHERE 1=1
AND e.name LIKE CONCAT('%', #{name}, '%')
AND e.gender = #{gender}
AND e.entry_date >= #{begin}
AND e.entry_date <= #{end}
ORDER BY e.entry_date DESC

SELECT *
FROM emp
WHERE username = #{username}
  AND password = #{password}
